import{_ as t,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Advanced Link Configuration","description":"","frontmatter":{"title":"Advanced Link Configuration","slug":"advanced-link-configuration"},"headers":[],"relativePath":"account-hub/advanced-link-configuration.md","filePath":"account-hub/advanced-link-configuration.md"}'),o={name:"account-hub/advanced-link-configuration.md"};function i(s,e,c,l,d,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<p>In the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">General tab</a> of App Settings page of the Branch Dashboard, you can change your advanced link settings.</p><h3 id="uri-scheme-deep-link-mode" tabindex="-1">URI scheme Deep Link mode <a class="header-anchor" href="#uri-scheme-deep-link-mode" aria-label="Permalink to &quot;URI scheme Deep Link mode&quot;">​</a></h3><p>This selector allows you to control how and when Branch uses URI schemes to open your app when Universal Links and Android App Links fail. See browser specifics in the docs <a href="./creating-a-deep-link.html#expected-link-behavior">here</a>.</p><table tabindex="0"><thead><tr><th>Deep Link Mode</th><th>Description</th></tr></thead><tbody><tr><td>Conservative</td><td>Conservative mode will never use URI schemes if there is a risk of error messages.</td></tr><tr><td>Intelligent</td><td>Intelligent mode is <strong>recommended</strong> and uses Branch data to safely use URI schemes everywhere, with the slight risk of error messages in certain browsers if the app is uninstalled.</td></tr><tr><td>Aggressive</td><td>Aggressive will force URI schemes everywhere, causing users without the app to see error messages in some browsers.</td></tr></tbody></table><h3 id="redirect-allowlist" tabindex="-1">Redirect allowlist <a class="header-anchor" href="#redirect-allowlist" aria-label="Permalink to &quot;Redirect allowlist&quot;">​</a></h3><p>With Branch, you have the ability to set a specific allowlist of domains that you can allow your Branch Links to redirect to (set to disabled by default). With the Redirect Allowlist, you can limit Branch Link redirection to specific web domains or URI schemes across your Branch platform. List each of the domains you want to limit redirection to. We also support a “*” for wildcard subdomains.</p><p>For example, if your allowlist includes <code>branch.io</code>, <code>*.branch.io</code>, and <code>myapp://</code>, your deep links can only redirect to domains like <code>branch.io</code>, <code>dashboard.branch.io</code>, or <code>myapp://</code>.</p><p>It is recommended that you include the app store domains that are relevant to the way users download your app. For example: <code>play.google.com</code> and <code>apps.apple.com</code> .</p><h3 id="match-type" tabindex="-1">Match type <a class="header-anchor" href="#match-type" aria-label="Permalink to &quot;Match type&quot;">​</a></h3><p>Setting Match Type determines the matching methodology Branch uses for your Links and App. Selecting <strong>Unique</strong> means that Branch will only make a deep link through install match if there is a single, unique outstanding footprint. For example, if you and your twin both have iPhone 5s with the same OS/version, etc, and click different links for the same app, then open the app up at the same time, we won’t deep link when Unique is selected. You probably don’t want this as it’s mostly for very special circumstances.</p><h3 id="local-currency" tabindex="-1">Local currency <a class="header-anchor" href="#local-currency" aria-label="Permalink to &quot;Local currency&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that in the <strong>legacy</strong> Branch experience, local currency settings are found under Configure → App Settings → General, as detailed here.</p><p>However in the <strong>new</strong> version of Branch, currency settings live under Configuration → <a href="./general-page.html">General</a>.</p></div><p>Set the local currency of your Branch Dashboard if it is not USD. By setting your local currency, you can analyze marketing spend (cost) and revenue in your local currency. This also allows direct cost data comparison with ad partners who report their spending in a currency other than USD.</p><p>A field called <strong>Local Currency</strong> will be available on the Dashboard showing the currency configured in your <a href="./paid-ads-analytics.html">Ads Analytics</a> and <a href="./unified-analytics.html">Unified Analytics</a>.</p><p>Note: The currency can only be set once through the Branch Dashboard to avoid some potential issues:<br> Historical data does not switch to the new local currency but would be labeled as such. As a result, the data prior to the currency change may show as inaccurate.<br> When changing the currency type, your cost data for the previous 7 days will be updated and may cause inaccuracies.</p><h3 id="other-settings" tabindex="-1">Other settings <a class="header-anchor" href="#other-settings" aria-label="Permalink to &quot;Other settings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Use UTM tags for analytics (for <a href="./creating-a-deep-link.html#long-links">Long Links</a>)</td><td>Disabled</td><td>If enabled, Branch will automatically set channel, feature, campaign, tags, and keywords based on UTM parameters. This only applies to Long Links, not links generated through the Dashboard, API, or SDKs.</td></tr><tr><td>Analytics mapping with UTM</td><td>Enabled</td><td>When redirecting to a web URL, Branch automatically passes through any values from the following Branch Link analytics tags as UTM parameters [~campaign -&gt; utm_campaign, ~channel -&gt; utm_source, ~feature -&gt; utm_medium]. If these UTM parameters are already detected on the URLs being redirected to, Branch will not overwrite them.</td></tr><tr><td>Enable Link Scraping</td><td>Disabled</td><td>This setting controls whether Branch scrapes the original web URL for Open Graph (OG) meta tags at the time of the click. - <strong>Applies to</strong>: Dynamic links and third-party links (for example, Email or Ads). - <strong>Does not apply to</strong>: Standard Short Links created in Branch or through the API (these are scraped immediately upon creation).</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Note</p><p>Enabling this ensures social link previews (for example, for iMessage or Slack) populate correctly for dynamic content. To minimize traffic to your servers, scrape results are cached for 24 hours.</p></div><p>| | Enable retrieving Last Attributed Touch Data via SDKs | Disabled | Allows the SDK to request the last known attribution data after the initial launch event. Use this to implement post-onboarding or deferred deep linking. It lets you retrieve routing data after a user signs up or signs in, rather than having to manually cache the data from the app&#39;s first open. | | Enable China Features | Disabled | China Features include the ability to collect IMEI on non-Google Android devices. |</p><h3 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h3><p>For changing the Link Domain for both of your LIVE and TEST Branch apps, the best practice is to change your LIVE app first and then add <em>test</em> somewhere in the new domain name for the TEST app.</p><p>Also please note that the <strong>LIVE and TEST apps cannot use the same customized Link Domain</strong>. For example, the LIVE app of <em>Branch Monster Factory</em> uses <code>monster-factory.app.link</code> for its LIVE app and <code>monster-factory.test-app.link</code> for its TEST app.</p>',22)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
